Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

### 1. Add the test package

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### 2. Create a fixture

```csharp
public class McpFixture : IAsyncLifetime
{
    private WebApplicationFactory<Program> _factory = default!;
    public HttpClient Client { get; private set; } = default!;

    public Task InitializeAsync()
    {
        _factory = new WebApplicationFactory<Program>();
        Client = _factory.CreateClient();
        return Task.CompletedTask;
    }

    public async Task DisposeAsync()
    {
        Client.Dispose();
        await _factory.DisposeAsync();
    }
}
```

### 3. Write protocol-level tests

Send real MCP JSON-RPC messages and assert on the responses:

```csharp
public class McpProtocolTests : IClassFixture<McpFixture>
{
    private readonly HttpClient _client;

    public McpProtocolTests(McpFixture fixture) => _client = fixture.Client;

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                clientInfo = new { name = "test-client", version = "1.0" },
                capabilities = new { }
            }
        };

        var response = await PostMcpAsync(request);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var result = json.GetProperty("result");
        Assert.Equal("2025-03-26", result.GetProperty("protocolVersion").GetString());
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        await InitializeSession();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var response = await PostMcpAsync(request);

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = json.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 3,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await PostMcpAsync(request);
        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.False(json.GetProperty("result").GetProperty("isError").GetBoolean());
    }

    private async Task InitializeSession() =>
        await PostMcpAsync(new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                clientInfo = new { name = "test", version = "1.0" },
                capabilities = new { }
            }
        });

    private Task<HttpResponseMessage> PostMcpAsync(object body) =>
        _client.PostAsJsonAsync("/mcp", body); // adjust path to your endpoint
}
```

### Key points

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer`
- **Full pipeline** — middleware, DI, routing all execute as in production
- **Override services** — use `.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test doubles (e.g., mock databases)
- **SSE transport** — if your server uses SSE, read the response stream with `ReadAsStreamAsync()` and parse `data:` lines
- Ensure `Program` is accessible (add `[assembly: InternalsVisibleTo("MyMcp.Tests")]` or a partial class)
